import * as LS from "../../src/lib/localstorage";
import { ConsentType } from "../../src/lib/consent";

describe("LS abstraction module", () => {
  describe("if localstorage exists in the browser", () => {
    afterEach(() => {
      window.localStorage.clear();
    });
    describe("setItem function", () => {
      it("should save the provided string in local storage against the provided key", () => {
        LS.setItem("testString", "testing123");
        expect(window.localStorage.getItem("testString")).toBe('"testing123"');
      });
      it("should save the provided object as a string in local storage against the provided key", () => {
        LS.setItem("testObject", { test: "testing123" });
        expect(window.localStorage.getItem("testObject")).toBe('{"test":"testing123"}');
      });
      it("Wil not set the value if it does not pass a cookie check", () => {
        LS.setItem("testString", "testing", "", ConsentType.Marketing);
        expect(window.localStorage.getItem("testString")).toBe(null);
      });
    });
    describe("getItem function", () => {
      it("should retrieve the string from local storage for the provided key", () => {
        window.localStorage.setItem("testString", JSON.stringify("testing123"));
        expect(LS.getItem("testString")).toBe("testing123");
      });
      it("should retrieve the object from local storage for the provided key", () => {
        window.localStorage.setItem("testObject", JSON.stringify({ test: "testing123" }));
        expect(LS.getItem("testObject")).toEqual({ test: "testing123" });
      });

      it("should return a string when the value is a string", () => {
        window.localStorage.setItem("testKey", "hello-world");
        expect(LS.getItem("testKey")).toBe("hello-world");
      });
    });
    describe("removeItem function", () => {
      it("should remove the item in local storage for the provided key", () => {
        window.localStorage.setItem("testString", "testing123");
        LS.removeItem("testString");
        expect(window.localStorage.getItem("testString")).toBe(null);
      });
    });
  });
  describe("if localStorage doesn't exist in the browser", () => {
    it("setItem should do nothing", () => {
      let savedLS = window.localStorage;
      delete window.localStorage;
      LS.setItem("testString", "testing123");
      window.localStorage = savedLS;
      expect(window.localStorage.getItem("testString")).toBe(null);
    });
    it("removeItem should do nothing", () => {
      let savedLS = window.localStorage;
      delete window.localStorage;
      expect(LS.removeItem("testString")).toBe(undefined);
      window.localStorage = savedLS;
      expect(window.localStorage.getItem("testString")).toBe(null);
    });
    it("getItem should return empty string", () => {
      let savedLS = window.localStorage;
      delete window.localStorage;
      expect(LS.getItem("testString")).toBe("");
      window.localStorage = savedLS;
    });
  });
});
